diffs.patch:
Index: infra/docker/services.ts
===================================================================
--- infra/docker/services.ts	
+++ infra/docker/services.ts	
@@ -0,0 +1,190 @@
+import * as command from "@pulumi/command/remote";
+import * as docker from "@pulumi/docker";
+import * as pulumi from "@pulumi/pulumi";
+
+interface DbCredentials {
+  USER: pulumi.Input<string>;
+  PASSWORD: pulumi.Input<string>;
+  NAME: pulumi.Input<string>;
+}
+
+export interface DockerServicesArgs {
+  publicIp: pulumi.Input<string>;
+  sshPrivateKey: pulumi.Input<string>;
+  appImage: pulumi.Input<string>;
+  appDomain: pulumi.Input<string>;
+  dbCredentials: DbCredentials;
+  betterAuthSecret: pulumi.Input<string>;
+  betterAuthUrl: pulumi.Input<string>;
+  r2AccessKeyId: pulumi.Input<string>;
+  r2SecretAccessKey: pulumi.Input<string>;
+  r2AccountId: pulumi.Input<string>;
+  r2BucketName: pulumi.Input<string>;
+  publicR2PublicUrl: pulumi.Input<string>;
+  publicPosthogKey?: pulumi.Input<string>;
+  publicPosthogHost?: pulumi.Input<string>;
+}
+
+export function setupDockerServices(args: DockerServicesArgs) {
+  const dockerProvider = new docker.Provider("docker-remote", {
+    host: pulumi.interpolate`ssh://ubuntu@${args.publicIp}`,
+    sshOpts: ["-o", "StrictHostKeyChecking=no"],
+  });
+
+  const sshConnection: command.ConnectionArgs = {
+    host: args.publicIp,
+    privateKey: args.sshPrivateKey,
+    user: "ubuntu",
+  };
+
+  const network = new docker.Network(
+    "alpauls-net",
+    { driver: "bridge", name: "alpauls-net" },
+    { provider: dockerProvider },
+  );
+
+  const dbDataVol = new docker.Volume(
+    "db-data",
+    { name: "db-data" },
+    { provider: dockerProvider },
+  );
+
+  const caddyDataVol = new docker.Volume(
+    "caddy-data",
+    { name: "caddy-data" },
+    { provider: dockerProvider },
+  );
+
+  const caddyConfigVol = new docker.Volume(
+    "caddy-config",
+    { name: "caddy-config" },
+    { provider: dockerProvider },
+  );
+
+  const dbContainer = new docker.Container(
+    "db",
+    {
+      envs: [
+        pulumi.interpolate`POSTGRES_USER=${args.dbCredentials.USER}`,
+        pulumi.interpolate`POSTGRES_PASSWORD=REDACTED,
+        pulumi.interpolate`POSTGRES_DB=${args.dbCredentials.NAME}`,
+      ],
+      healthcheck: {
+        interval: "5s",
+        retries: 5,
+        tests: [
+          "CMD-SHELL",
+          pulumi.interpolate`pg_isready -U ${args.dbCredentials.USER}`,
+        ],
+        timeout: "5s",
+      },
+      image: "postgres:18-alpine",
+      mounts: [
+        {
+          source: dbDataVol.name,
+          target: "/var/lib/postgresql/18/data",
+          type: "volume",
+        },
+      ],
+      name: "db",
+      networksAdvanced: [{ name: network.name }],
+      restart: "always",
+    },
+    { provider: dockerProvider },
+  );
+
+  const appContainer = new docker.Container(
+    "app",
+    {
+      envs: [
+        pulumi.interpolate`DATABASE_URL=REDACTED`,
+        pulumi.interpolate`BETTER_AUTH_SECRET=${args.betterAuthSecret}`,
+        pulumi.interpolate`BETTER_AUTH_URL=${args.betterAuthUrl}`,
+        pulumi.interpolate`R2_ACCESS_KEY_ID=${args.r2AccessKeyId}`,
+        pulumi.interpolate`R2_SECRET_ACCESS_KEY=${args.r2SecretAccessKey}`,
+        pulumi.interpolate`R2_ACCOUNT_ID=${args.r2AccountId}`,
+        pulumi.interpolate`R2_BUCKET_NAME=${args.r2BucketName}`,
+        pulumi.interpolate`PUBLIC_R2_PUBLIC_URL=${args.publicR2PublicUrl}`,
+        pulumi.interpolate`PUBLIC_POSTHOG_KEY=${args.publicPosthogKey ?? ""}`,
+        pulumi.interpolate`PUBLIC_POSTHOG_HOST=${args.publicPosthogHost ?? ""}`,
+      ],
+      image: args.appImage,
+      name: "app",
+      networksAdvanced: [{ name: network.name }],
+      restart: "always",
+    },
+    { dependsOn: [dbContainer], provider: dockerProvider },
+  );
+
+  const caddyfileContent = pulumi.interpolate`${args.appDomain} {
+  reverse_proxy app:3020
+}`;
+
+  const caddyContainer = new docker.Container(
+    "caddy",
+    {
+      image: "caddy:2-alpine",
+      mounts: [
+        {
+          source: caddyDataVol.name,
+          target: "/data",
+          type: "volume",
+        },
+        {
+          source: caddyConfigVol.name,
+          target: "/config",
+          type: "volume",
+        },
+      ],
+      name: "caddy",
+      networksAdvanced: [{ name: network.name }],
+      ports: [
+        { external: 80, internal: 80, ip: "0.0.0.0", protocol: "tcp" },
+        { external: 443, internal: 443, ip: "0.0.0.0", protocol: "tcp" },
+      ],
+      restart: "always",
+      uploads: [
+        {
+          content: caddyfileContent,
+          file: "/etc/caddy/Caddyfile",
+        },
+      ],
+    },
+    { dependsOn: [appContainer], provider: dockerProvider },
+  );
+
+  const envContent = pulumi.interpolate`APP_IMAGE=${args.appImage}
+DB_USER=${args.dbCredentials.USER}
+DB_PASSWORD=${args.dbCredentials.PASSWORD}
+DB_NAME=${args.dbCredentials.NAME}
+BETTER_AUTH_SECRET=${args.betterAuthSecret}
+BETTER_AUTH_URL=${args.betterAuthUrl}
+R2_ACCESS_KEY_ID=${args.r2AccessKeyId}
+R2_SECRET_ACCESS_KEY=${args.r2SecretAccessKey}
+R2_ACCOUNT_ID=${args.r2AccountId}
+R2_BUCKET_NAME=${args.r2BucketName}
+PUBLIC_R2_PUBLIC_URL=${args.publicR2PublicUrl}
+PUBLIC_POSTHOG_KEY=${args.publicPosthogKey ?? ""}
+PUBLIC_POSTHOG_HOST=${args.publicPosthogHost ?? ""}`;
+
+  const writeEnvFile = new command.Command(
+    "write-env-file",
+    {
+      connection: sshConnection,
+      create: pulumi.interpolate`mkdir -p /opt/alpauls-ats && cat > /opt/alpauls-ats/.env << 'ENVEOF'\n${envContent}\nENVEOF`,
+      triggers: [envContent],
+      update: pulumi.interpolate`cat > /opt/alpauls-ats/.env << 'ENVEOF'\n${envContent}\nENVEOF`,
+    },
+    { dependsOn: [dbContainer, appContainer, caddyContainer] },
+  );
+
+  return {
+    appContainer,
+    caddyContainer,
+    caddyContainerId: caddyContainer.id,
+    dbContainer,
+    dbContainerId: dbContainer.id,
+    network,
+    writeEnvFile,
+  };
+}

Index: infra/leo/instance.ts
===================================================================
--- infra/leo/instance.ts	
+++ infra/leo/instance.ts	
@@ -1,134 +1,143 @@
 import { core, identity } from "@pulumi/oci";

+// TODO: SETUP AN APP FOR SYSTEM MONITORING AND DOCKER MONITORING
+//
+// TODO: DEPLOYMENTS: ENVIRONMENT / CI-CD / ROLLBACKS / SKEW PROTECTION / ROLLING RELEASES
+// TODO: REMOTE BUILDS (USE GITHUB ACTIONS)
+// TODO: AUTOMATED-BACKUPS
+//
+//  TODO: FIREWALL / RATE LIMITING / DDOS / CDN
+// TODO: MANAGED STORAGE / MANAGED DATABASE / MANAGED WORKFLOWS-QUEUES-CRONS / MANAGED AI-GATEWAY / MANAGED OBSERVABILITY
+
 export function setupLeoInstance({
   projectName,
   compartmentId,
   sshPublicKey,
 }: {
   projectName: string;
   sshPublicKey: string;
   compartmentId: string;
 }) {
   // ------------ Network ------------

   const vcn = new core.Vcn("alpauls-ats-vcn", {
     cidrBlocks: ["10.0.0.0/16"],
     compartmentId,
     displayName: "alpauls-ats-vcn",
     dnsLabel: "alpauls-ats",
   });

   const igw = new core.InternetGateway("alpauls-ats-igw", {
     compartmentId,
     displayName: "alpauls-ats-igw",
     enabled: true,
     vcnId: vcn.id,
   });

   // ------------ Network ------------

   const routeTable = new core.RouteTable(`leo-rt-${projectName}`, {
     compartmentId,
     displayName: `leo-rt-${projectName}`,
     routeRules: [{ destination: "0.0.0.0/0", networkEntityId: igw.id }],
     vcnId: vcn.id,
   });

   const securityList = new core.SecurityList(`leo-sl-${projectName}`, {
     compartmentId,
     displayName: `leo-sl-${projectName}`,
     egressSecurityRules: [{ destination: "0.0.0.0/0", protocol: "all" }],
     ingressSecurityRules: [
       {
         protocol: "6",
         source: "0.0.0.0/0",
         tcpOptions: { sourcePortRange: { max: 22, min: 22 } },
       },
       {
         protocol: "6",
         source: "0.0.0.0/0",
         tcpOptions: { sourcePortRange: { max: 80, min: 80 } },
       },
       {
         protocol: "6",
         source: "0.0.0.0/0",
         tcpOptions: { sourcePortRange: { max: 443, min: 443 } },
       },
     ],
     vcnId: vcn.id,
   });

   const subnet = new core.Subnet(`leo-subnet-${projectName}`, {
     cidrBlock: "10.0.1.0/24",
     compartmentId,
     displayName: `leo-subnet-${projectName}`,
     dnsLabel: `leo-subnet-${projectName}`,
     routeTableId: routeTable.id,
     securityListIds: [securityList.id],
     vcnId: vcn.id,
   });

   // ------------ Instance ------------

   const ads = identity.getAvailabilityDomainsOutput({ compartmentId });

   const images = core.getImagesOutput({
     compartmentId,
     operatingSystem: "Canonical Ubuntu",
     operatingSystemVersion: "22.04",
     shape: "VM.Standard.A1.Flex",
   });

   const userData = `#cloud-config
 package_update: true
 package_upgrade: true

 packages:
   - curl
   - ufw
   - ca-certificates
   - gnupg
   - docker

 runcmd:
   - install -m 0755 -d /etc/apt/keyrings
   - curl -fsSL https://download.docker.com/linux/ubuntu/gpg | gpg --dearmor -o /etc/apt/keyrings/docker.gpg
   - echo "deb [arch=arm64 signed-by=/etc/apt/keyrings/docker.gpg] https://download.docker.com/linux/ubuntu $(lsb_release -cs) stable" > /etc/apt/sources.list.d/docker.list
   - apt-get update
   - apt-get install -y docker-ce docker-ce-cli containerd.io docker-compose-plugin
   - systemctl enable docker
   - systemctl start docker
   - ufw allow 22/tcp
   - ufw allow 80/tcp
   - ufw allow 443/tcp
   - ufw --force enable
 `;

   const instance = new core.Instance(`leo-vm-${projectName}`, {
     availabilityDomain: ads.availabilityDomains[0].name,
     compartmentId,
     createVnicDetails: {
       assignPublicIp: "true",
       hostnameLabel: `leo-vm-${projectName}`,
       privateIp: "10.0.1.10",
       subnetId: subnet.id,
     },
     displayName: `leo-vm-${projectName}`,
     metadata: {
       ssh_authorized_keys: sshPublicKey,
       user_data: userData,
     },
     shape: "VM.Standard.A1.Flex",
     shapeConfig: {
       memoryInGbs: 6,
       ocpus: 1,
     },
     sourceDetails: {
       bootVolumeSizeInGbs: "50",
       sourceId: images.id,
       sourceType: "image",
     },
   });

-  return { igw, instance, vcn };
+  return { igw, instance, publicIp: instance.publicIp, vcn };
 }

